const title = document.querySelector('h1');
const body = document.body;
const profileImg = document.querySelector('#profile');

// 1. Changing Text
title.innerText = 'Welcome Back!';

// 2. Toggling Classes (Best way to handle CSS changes)
// If the class is there, it removes it. If it's missing, it adds it.
body.classList.toggle('dark-theme'); 

// 3. Changing Attributes
profileImg.setAttribute('src', 'new-photo.jpg');
profileImg.alt = 'User profile picture'; // Direct property access also works

// 4. Changing Inline Styles (Use sparingly)
title.style.color = 'blue';
title.style.fontSize = '3rem';
